--
-- TOC entry 236 (class 1259 OID 49533)
-- Name: AttendanceDashboard; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."AttendanceDashboard" AS
 SELECT c.name AS "companyName",
    b."branchName",
    e.name AS "employeeName",
    e.department,
    a.date,
    a."clockIn",
    a."clockOut",
        CASE
            WHEN (a."clockIn" IS NOT NULL) THEN 'Present'::text
            ELSE 'Absent'::text
        END AS status
   FROM (((public."Company" c
     JOIN public."Branch" b ON ((c.id = b."companyId")))
     JOIN public."Employee" e ON ((b.id = e."branchId")))
     LEFT JOIN public."Attendance" a ON ((e.id = a."employeeId")));


ALTER VIEW public."AttendanceDashboard" OWNER TO postgres;

